const body = $json.body || $json;
const headers = $json.headers || {};

const expectedKey = $env.FLOWISE_API_KEY;
const providedKey = headers['x-api-key'] || headers['X-API-Key'];

// Reject keys exceeding max length to prevent truncation attacks
const MAX_KEY_LENGTH = 128;

function safeCompare(a, b) {
  // Reject keys exceeding max length first (length is not secret)
  if (a.length > MAX_KEY_LENGTH || b.length > MAX_KEY_LENGTH) {
    return false;
  }

  // Constant-time comparison (no padding, no branching on secret data)
  // If lengths differ, we still compare to avoid timing leaks, but will return false
  const len = Math.max(a.length, b.length);
  let result = a.length ^ b.length;  // Non-zero if lengths differ

  for (let i = 0; i < len; i++) {
    // When index exceeds string length, use 0 (null byte) to avoid out-of-bounds
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  return result === 0;
}

if (expectedKey && expectedKey.length > 0) {
  if (!providedKey) {
    return [{ json: { error: 'Authentication required', code: 401 } }];
  }
  if (!safeCompare(expectedKey, providedKey)) {
    return [{ json: { error: 'Invalid API key', code: 403 } }];
  }
}

const chatflowId = body.chatflowId || $env.FLOWISE_DEFAULT_CHATFLOW_ID;
if (!chatflowId) {
  return [{ json: { error: 'chatflowId required', code: 400 } }];
}

// Validate chatflowId format (UUID v4 or alphanumeric with hyphens only)
const validIdPattern = /^[a-zA-Z0-9-]+$/;
if (!validIdPattern.test(chatflowId)) {
  return [{ json: { error: 'Invalid chatflowId format', code: 400 } }];
}

return [{
  json: {
    question: body.question || body.message || body.prompt || 'Hello',
    chatflowId: chatflowId,
    streaming: body.streaming || false,
    overrideConfig: body.overrideConfig || {}
  }
}];

const response = $json;

// Handle HTTP errors (when continueOnFail catches them)
if ($('Flowise API').last().error) {
  return [{
    json: {
      error: 'Upstream service error',
      code: 502
    }
  }];
}

if (response.error) {
  return [{
    json: {
      error: 'Request processing failed',
      code: response.code || 500
    }
  }];
}

return [{
  json: {
    text: response.text || response.response || 'No response',
    chatId: response.chatId,
    chatMessageId: response.chatMessageId,
    sourceDocuments: response.sourceDocuments || [],
    usedTools: response.usedTools || []
  }
}];
